import React, { useEffect, useState } from "react";
import {
  Box,
  Button,
  Typography,
  Paper,
  CircularProgress,
  Alert,
} from "@mui/material";
import { getAllRiders, approveRider, rejectRider } from "../services/api";
import { useNavigate } from "react-router-dom";

export default function AdminDashboard() {
  const navigate = useNavigate();
  const [riders, setRiders] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");

  useEffect(() => {
    const isAdmin = localStorage.getItem("adminLoggedIn");
    if (!isAdmin) {
      navigate("/admin-login"); // redirect if not logged in
    } else {
      fetchRiders();
    }
  }, [navigate]);

  const fetchRiders = async () => {
    setLoading(true);
    try {
      // 🚨 since this is static login, skip JWT. Just call API directly
      const res = await getAllRiders(localStorage.getItem("token"));
      if (res.data?.success) setRiders(res.data.riders);
      else setError("Failed to fetch riders");
    } catch (err) {
      console.error(err);
      setError("Server error");
    } finally {
      setLoading(false);
    }
  };

  const handleApprove = async (id) => {
    await approveRider(localStorage.getItem("token"), id);
    fetchRiders();
  };

  const handleReject = async (id) => {
    await rejectRider(localStorage.getItem("token"), id);
    fetchRiders();
  };

  const handleLogout = () => {
    localStorage.removeItem("adminLoggedIn");
    navigate("/admin-login");
  };

  if (loading) return <Box sx={{ p: 4, textAlign: "center" }}><CircularProgress /></Box>;
  if (error) return <Box sx={{ p: 4 }}><Alert severity="error">{error}</Alert></Box>;

  return (
    <Box sx={{ p: 4 }}>
      <Typography variant="h4" sx={{ mb: 3 }}>
        Admin Dashboard - Rider Approvals
      </Typography>
      {riders.map((rider) => (
        <Paper key={rider._id} sx={{ p: 2, mb: 2 }}>
          <Typography><b>Name:</b> {rider.fullName}</Typography>
          <Typography><b>Mobile:</b> {rider.mobile}</Typography>
          <Typography><b>Email:</b> {rider.email}</Typography>
          <Typography><b>Status:</b> {rider.approvalStatus}</Typography>
          <Box sx={{ mt: 2, display: "flex", gap: 2 }}>
            <Button
              variant="contained"
              color="success"
              onClick={() => handleApprove(rider._id)}
            >
              Approve
            </Button>
            <Button
              variant="contained"
              color="error"
              onClick={() => handleReject(rider._id)}
            >
              Reject
            </Button>
          </Box>
        </Paper>
      ))}

      <Button sx={{ mt: 3 }} variant="contained" color="error" onClick={handleLogout}>
        Logout
      </Button>
    </Box>
  );
}
